DOMAIN_WEIGHTS: dict[AssessmentDomain, float] = {
    AssessmentDomain.DATA_PRIVACY:  0.30,
    AssessmentDomain.SECURITY:      0.25,
    AssessmentDomain.MODEL_SAFETY:  0.20,
    AssessmentDomain.RESILIENCE:    0.15,
    AssessmentDomain.REGULATORY:    0.10,
}

def compute_overall_rating(scores: list[DomainScore]) -> TPRMRating:
    """
    Weighted average across domains. Any domain raw_score < 0.4 triggers
    an immediate HIGH rating regardless of average (material-weakness rule).
    """
    for ds in scores:
        if ds.raw_score < 0.40:
            return TPRMRating.HIGH          # material weakness in one domain

    weighted_avg = sum(ds.weighted for ds in scores) / sum(ds.weight for ds in scores)

    if weighted_avg >= 0.80:
        return TPRMRating.LOW
    elif weighted_avg >= 0.60:
        return TPRMRating.MODERATE
    elif weighted_avg >= 0.40:
        return TPRMRating.HIGH
    return TPRMRating.CRITICAL

@dataclass
class TPRMAssessment:
    vendor: VendorProfile
    scores: list[DomainScore]
    overall: TPRMRating = field(init=False)
    assessed_by: str = "risk-team"
    assessed_at: str = ""

    def __post_init__(self):
        self.overall = compute_overall_rating(self.scores)

    def material_findings(self) -> list[tuple[AssessmentDomain, str]]:
        out = []
        for ds in self.scores:
            for f in ds.findings:
                out.append((ds.domain, f))
        return out

    def summary(self) -> str:
        lines = [
            f"Vendor: {self.vendor.name} ({self.vendor.service_type})",
            f"Tier: {self.vendor.tier.name}",
            f"Overall TPRM Rating: {self.overall.value.upper()}",
            "",
            "Domain Scores:",
        ]
        for ds in self.scores:
            lines.append(f"  {ds.domain.value:<18} {ds.raw_score:.2f}  (weight {ds.weight:.0%})")
        if findings := self.material_findings():
            lines.append("\nMaterial Findings:")
            for domain, finding in findings:
                lines.append(f"  [{domain.value}] {finding}")
        return "\n".join(lines)

from dataclasses import dataclass

@dataclass
class ContractualRequirement:
    clause: str
    description: str
    triggered_by: str   # rating level or specific finding

STANDARD_CLAUSES: dict[TPRMRating, list[ContractualRequirement]] = {
    TPRMRating.LOW: [
        ContractualRequirement("DATA-01", "Standard DPA with GDPR Article 28 provisions", "always"),
        ContractualRequirement("SEC-01",  "Annual pen-test reports on request", "always"),
    ],
    TPRMRating.MODERATE: [
        ContractualRequirement("DATA-01", "Standard DPA", "always"),
        ContractualRequirement("DATA-02", "Data residency locked to EU/US", "MODERATE+"),
        ContractualRequirement("SEC-02",  "Quarterly security briefing", "MODERATE+"),
        ContractualRequirement("RES-01",  "99.9% SLA with financial remedy clause", "MODERATE+"),
        ContractualRequirement("AI-01",   "Model change notification (14-day notice)", "MODERATE+"),
    ],
    TPRMRating.HIGH: [
        ContractualRequirement("DATA-03", "Prompt/response data NOT used for training", "HIGH"),
        ContractualRequirement("SEC-03",  "Right-to-audit clause (annual)", "HIGH"),
        ContractualRequirement("SEC-04",  "Real-time incident notification (1h SLA)", "HIGH"),
        ContractualRequirement("AI-02",   "Model card and alignment report provided", "HIGH"),
        ContractualRequirement("AI-03",   "Subprocessor list with 30-day change notice", "HIGH"),
        ContractualRequirement("EXIT-01", "Data deletion certificate within 30 days of termination", "HIGH"),
    ],
}

def determine_contract_terms(assessment: TPRMAssessment) -> list[ContractualRequirement]:
    """Aggregate clauses for the assessed rating and all more-restrictive tiers."""
    result = []
    for rating in [TPRMRating.LOW, TPRMRating.MODERATE, TPRMRating.HIGH]:
        result.extend(STANDARD_CLAUSES.get(rating, []))
        if rating == assessment.overall:
            break
    return result

def approve_vendor(assessment: TPRMAssessment) -> tuple[bool, str]:
    """Return (approved, reason). CRITICAL rating is always rejected."""
    if assessment.overall == TPRMRating.CRITICAL:
        return False, "Vendor rated CRITICAL — rejection required. Initiate exit or remediation plan."
    if assessment.overall == TPRMRating.HIGH and assessment.vendor.tier == VendorTier.TIER_1:
        return False, "HIGH-rated Tier-1 vendor requires CISO sign-off before approval."
    return True, f"Approved with {len(determine_contract_terms(assessment))} contractual controls."
